use std::ffi::{CStr, CString};
use std::os::raw::c_char;

struct TelemetryRecord {
    timestamp: i64,
    sensor_id: String,
    value: f64,
}

extern "C" {
    fn get_next_log_entry() -> *mut c_char;
    fn is_end_of_stream() -> bool;
}

fn process_telemetry_data() -> Vec<TelemetryRecord> {
    let mut records = Vec::new();

    loop {
        if unsafe { std::ptr::null_mut() == get_next_log_entry() } && unsafe { is_end_of_stream() } {
            break;
        }

        let raw_ptr = unsafe { get_next_log_entry() };
        if raw_ptr.is_null() { break; }

        let c_str = unsafe { CStr::from_ptr(raw_ptr) };
        let log_line = match c_str.to_str() {
            Ok(s) => s.trim().to_string(),
            Err(_) => continue,
        };

        if let Some(record) = parse_log_line(&log_line) {
            records.push(record);
        }
    }
    records
}

fn parse_log_line(line: &str) -> Option<TelemetryRecord> {
    let parts: Vec<&str> = line.split("|").collect();
    if parts.len() != 3 {
        return None;
    }

    let timestamp = parts[0].parse::<i64>().ok()?;
    let sensor_id = parts[1].trim().to_string();
    let value = parts[2].parse::<f64>().ok()?;

    Some(TelemetryRecord {
        timestamp,
        sensor_id,
        value,
    })
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("Starting data ingestion process...");
    let records = process_telemetry_data();
    println!("Successfully processed {} records.", records.len());
    Ok(())
}

use std::ffi::{CStr, c_void};
use std::os::raw::c_char;

fn process_usernames(user_ptr: *mut c_char, count: usize) -> Result<Vec<String>, &'static str> {
    let mut results = Vec::with_capacity(count);
    for i in 0..count {
        let item_ptr = unsafe { user_ptr.add(i) };
        if item_ptr.is_null() {
            return Err("Encountered a null pointer mid-array.");
        }
        let c_str = unsafe { CStr::from_ptr(item_ptr) };
        match c_str.to_str().ok() {
            Some(s) => results.push(s.to_string()),
            None => return Err("Failed to convert UTF-8 sequence."),
        }
    }
    Ok(results)
}

fn main() {
    let usernames_c_array: Vec<i32> = vec![1, 2, 3];
    let mut buffer = Vec::new();
    for &id in &usernames_c_array {
        let name = format!("user_{}", id);
        buffer.extend_from_slice(name.as_bytes());
        buffer.push(b'\0');
    }

    let raw_ptr: *mut c_char = buffer.as_ptr() as *mut c_char;
    let count = usernames_c_array.len();

    match process_usernames(raw_ptr, count) {
        Ok(names) => println!("Successfully processed {} names: {:?}", names.len(), names),
        Err(e) => eprintln!("Error processing usernames: {}", e),
    }
}

use std::ffi::CString;
use std::os::raw::c_char;

struct PacketData {
    source_ip: String,
    destination_ip: String
}

extern "C" {
    fn process_packet(data_ptr: *const c_char, len: usize);
}

fn main() {
    let packet = PacketData {
        source_ip: "192.168.1.10".to_string(),
        destination_ip: "203.0.113.5".to_string()
    };

    let combined_data = format!("Source: {}, Dest: {}", packet.source_ip, packet.destination_ip);

    let c_string = CString::new(combined_data).expect("Failed to convert string to CString");

    unsafe {
        process_packet(c_string.as_ptr(), 0);
    }

    drop(c_string);
}

use std::ffi::{CStr, CString};
use std::os::raw::c_char;

struct ChessBoard {
    history: Vec<i32>,
}

impl ChessBoard {
    fn new() -> Self {
        ChessBoard { history: Vec::new() }
    }

    fn process_move_data(input_ptr: *const c_char, len: usize) -> Result<(), String> {
        if input_ptr.is_null() {
            return Err("Null pointer received for move data.".to_string());
        }

        let slice = unsafe { std::slice::from_raw_parts(input_ptr, len) };
        let c_str = unsafe { CStr::from_ptr(slice.as_ptr()) };
        let result = c_str;

        match result.to_bytes() {
            &[b] if b == b'E' => Ok(()),
            _ => Err("Invalid move data format.".to_string()),
        }
    }
}

fn main() -> Result<(), String> {
    let board = ChessBoard::new();
    let move_input = CString::new("E").unwrap();
    let len = move_input.as_bytes().len();

    ChessBoard::process_move_data(move_input.as_ptr(), len)?;

    println!("Successfully processed board state.");

    Ok(())
}
